// Footer Component — Site-wide footer
import React from 'react';
import { Link } from 'react-router-dom';
import './Footer.css';

const Footer = () => {
  return (
    <footer className="footer">
      <div className="container">
        <div className="footer-grid">

          {/* Brand Column */}
          <div className="footer-brand">
            <Link to="/" className="footer-logo">
              <span>💙</span> Fund<span className="logo-accent">It</span>
            </Link>
            <p className="footer-tagline">
              India's trusted crowdfunding platform. Empowering people to raise funds for medical emergencies, education, and social causes.
            </p>
          </div>

          {/* Quick Links */}
          <div className="footer-col">
            <h4>Quick Links</h4>
            <Link to="/">Browse Campaigns</Link>
            <Link to="/create-campaign">Start a Campaign</Link>
            <Link to="/login">Login</Link>
            <Link to="/register">Sign Up</Link>
          </div>

          {/* Categories */}
          <div className="footer-col">
            <h4>Categories</h4>
            <span>🏥 Medical</span>
            <span>📚 Education</span>
            <span>🤝 Social</span>
            <span>🌿 Environment</span>
            <span>⛑️ Disaster Relief</span>
          </div>

          {/* Contact */}
          <div className="footer-col">
            <h4>Contact</h4>
            <span>📧 support@fundit.in</span>
            <span>📞 +91-9876543210</span>
            <span>📍 Chandigarh, India</span>
          </div>
        </div>

        {/* Bottom Bar */}
        <div className="footer-bottom">
          <p>© {new Date().getFullYear()} FundIt. All rights reserved.</p>
          <p>Built with 💙 for social impact</p>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
